CREATE TABLE IF NOT EXISTS sup_supplier_contract (
 contract_id bigint NOT NULL,contract_no varchar(64) NOT NULL,supplier_id bigint NOT NULL,quote_id bigint NULL,price_agreement_ref varchar(64) NULL,contract_type varchar(32) NOT NULL,contract_status smallint NOT NULL COMMENT '1草稿 2审批中 3已生效 4已终止 5已到期',effective_from date NOT NULL,effective_to date NOT NULL,terms_json json NOT NULL,attachment_url varchar(512) NULL,termination_reason varchar(512) NULL,created_by bigint NOT NULL,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_by bigint NULL,updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),version int NOT NULL DEFAULT 0,deleted tinyint NOT NULL DEFAULT 0,
 PRIMARY KEY(contract_id),UNIQUE KEY uk_sup_contract_no(contract_no),KEY idx_sup_contract_supplier_status(supplier_id,contract_status,effective_to),KEY idx_sup_contract_quote(quote_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='供应商合同聚合';
